import{c as t,Q as a,j as i,m as o}from"./chunks/framework.CLEOx5cX.js";const u=JSON.parse('{"title":"What is FiveM Escrow?","description":"","frontmatter":{},"headers":[],"relativePath":"fivem-escrow.md","filePath":"fivem-escrow.md","lastUpdated":1780286224000}'),r={name:"fivem-escrow.md"};function s(c,e,n,l,p,d){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="what-is-fivem-escrow" tabindex="-1">What is FiveM Escrow? <a class="header-anchor" href="#what-is-fivem-escrow" aria-label="Permalink to &quot;What is FiveM Escrow?&quot;">​</a></h1><p>FiveM Escrow is a protection system used by resource creators to protect selected files while still allowing server owners to configure and use the script.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>An escrowed script can contain both protected and open files.</p><p>Protected files usually contain critical logic, licensing, anti-tamper checks, or source code that should not be modified directly.</p><p>Open files usually contain configuration, framework adapters, functions, language files, public events, or other integration points.</p><h2 id="how-crabo-scripts-use-it" tabindex="-1">How Crabo Scripts Use It <a class="header-anchor" href="#how-crabo-scripts-use-it" aria-label="Permalink to &quot;How Crabo Scripts Use It&quot;">​</a></h2><p>Crabo scripts are designed so the critical core can stay protected while the adaptation layer remains open.</p><p>For example, <code>oskar_battlepass</code> keeps framework-specific logic in open adapter files, while the main protected core can keep the sensitive logic closed.</p><h2 id="what-you-can-edit" tabindex="-1">What You Can Edit <a class="header-anchor" href="#what-you-can-edit" aria-label="Permalink to &quot;What You Can Edit&quot;">​</a></h2><p>You can usually edit:</p><ul><li>Configuration files.</li><li>Framework adapter files.</li><li>Open function files.</li><li>Public integration files.</li><li>Documentation files.</li></ul><p>Avoid editing protected core files unless the resource specifically documents that they are open and safe to change.</p>',13)])])}const f=t(r,[["render",s]]);export{u as __pageData,f as default};
